// Phong Illumination Model
// Input: surface normal N, light direction L, view direction V
// Material: ka, kd, ks, shininess n
// Light: Ia (ambient), Ii (intensity)

FUNCTION PhongIllumination(N, L, V, ka, kd, ks, n, Ia, Ii):
 // Normalize all vectors
 N = normalize(N)
 L = normalize(L)
 V = normalize(V)

 // Ambient component
 I_ambient = ka * Ia

 // Diffuse component (Lambert)
 NdotL = dot(N, L)
 IF NdotL > 0 THEN:
 I_diffuse = kd * Ii * NdotL
 ELSE:
 I_diffuse = 0

 // Specular component
 R = reflect(-L, N) // R = 2(N·L)N - L
 RdotV = dot(R, V)
 IF RdotV > 0 AND NdotL > 0 THEN:
 I_specular = ks * Ii * (RdotV ^ n)
 ELSE:
 I_specular = 0

 // Total illumination
 RETURN I_ambient + I_diffuse + I_specular
END FUNCTION

// Point Light Attenuation
// d = distance from light to surface
// c1, c2, c3 = attenuation coefficients

FUNCTION CalculateAttenuation(d, c1, c2, c3):
 // Avoid division by zero
 IF d < 0.001 THEN:
 RETURN 1.0

 // Standard attenuation formula
 attenuation = 1.0 / (c1 + c2 * d + c3 * d * d)

 // Clamp to reasonable range
 RETURN clamp(attenuation, 0.0, 1.0)
END FUNCTION

// Example usage:
// Close range (d=1): f(1) = 1/(0 + 1 + 0) = 1.0
// Medium (d=5): f(5) = 1/(0 + 5 + 25) = 0.033
// Far (d=10): f(10) = 1/(0 + 10 + 100) = 0.009

// Spotlight Intensity Calculation
// L = direction from light to surface point (normalized)
// D = spotlight direction (normalized)
// cutoff = cone angle in radians
// exponent = falloff control

FUNCTION SpotlightIntensity(L, D, cutoff, exponent):
 // Angle between light direction and spotlight axis
 cos_angle = dot(-L, D) // -L because L points toward light

 // Angle of the cone edge
 cos_cutoff = cos(cutoff)

 // Check if point is inside the cone
 IF cos_angle < cos_cutoff THEN:
 RETURN 0.0 // Outside cone - no illumination

 // Calculate falloff from center to edge
 // Higher exponent = sharper edge
 spot = (cos_angle - cos_cutoff) / (1.0 - cos_cutoff)
 spot = spot ^ exponent

 RETURN spot
END FUNCTION

// Combined with other lighting:
// total = ambient + diffuse + specular * spotlight_factor

// Blinn-Phong Illumination (optimized Phong)
// Replaces R·V with N·H where H is halfway vector

FUNCTION BlinnPhong(N, L, V, ka, kd, ks, n, Ia, Ii):
 N = normalize(N)
 L = normalize(L)
 V = normalize(V)

 // Ambient
 I_ambient = ka * Ia

 // Diffuse (same as Phong)
 NdotL = max(0, dot(N, L))
 I_diffuse = kd * Ii * NdotL

 // Blinn-Phong specular (halfway vector)
 H = normalize(L + V) // Halfway vector
 NdotH = dot(N, H)

 IF NdotH > 0 THEN:
 I_specular = ks * Ii * (NdotH ^ n)
 ELSE:
 I_specular = 0

 RETURN I_ambient + I_diffuse + I_specular
END FUNCTION

// Key advantage: H always in upper hemisphere,
// avoids R·V negatives that occur when V opposite to R
